                                        }
                }
            } else if (!("yes".equalsIgnoreCase(value) || "true".equalsIgnoreCase(value) || "1".equalsIgnoreCase(value))) {
                                continue;
            }
            cmd.addOption(opt);
            updateRequiredOptions(opt);
        }
    }
