                if (!lockHeld) {
                    if (violations == null)
                        violations = new ArrayList<Short>();
                    violations.add((short) 7);
                }
            }
        }
    }
    if (violations != null) {
        log.debug(" violating metadata mutation : " + mutation);
    }
    return violations;
