        FileSystem fs = volume.getFileSystem();
        if (ViewFSUtils.isViewFS(fs)) {
            try {
                FileSystem resolvedFs = ViewFSUtils.resolvePath(fs, new Path("/")).getFileSystem(fs.getConf());
