                break;
            }
        } else if (readIf("jcr:root")) {
                        if (!pathPattern.isEmpty()) {
                throw getSyntaxError("jcr:root needs to be at the beginning");
            }
            if (readIf("/")) {
                                currentSelector.path = "/";
