                    currentSelector.isDescendant = true;
                } else {
                    currentSelector.isChild = true;
                }
            } else {
                                pathPattern = "/%";
                currentSelector.path = "/";
                shortcut = true;
            }
        } else if (readIf("/")) {
                        pathPattern += "%";
            if (currentSelector.isDescendant) {
                                nextSelector(true);
            }
            currentSelector.isDescendant = true;
        } else {
                        pathPattern += "/";
            if (startOfQuery) {
                currentSelector.path = "/";
